import{_ as t,o as e,c as a,ag as r}from"./chunks/framework.wqPkq5Rj.js";const d=JSON.parse('{"title":"接入外部工具","description":"","frontmatter":{},"headers":[],"relativePath":"setup/integrations.md","filePath":"setup/integrations.md","lastUpdated":1777169627000}'),i={name:"setup/integrations.md"};function l(n,o,p,s,m,h){return e(),a("div",null,[...o[0]||(o[0]=[r('<h1 id="接入外部工具" tabindex="-1">接入外部工具 <a class="header-anchor" href="#接入外部工具" aria-label="Permalink to &quot;接入外部工具&quot;">​</a></h1><p>Moxt 的核心能力之一是让 momo 连接你们已有的工具。接入越多，momo 能做的事越多。</p><hr><h2 id="slack" tabindex="-1">Slack <a class="header-anchor" href="#slack" aria-label="Permalink to &quot;Slack&quot;">​</a></h2><p>接入之后，两件事变得可能：</p><p><strong>在 Slack 里直接给 momo 发指令</strong></p><blockquote><p>@momo 把这周的用户反馈汇总一下</p></blockquote><p>不用打开 Moxt，在 Slack 里说一句话，结果直接出现在 Workspace 里，Slack 里同步推送摘要。</p><p><strong>让 momo 监测 Slack 里的信息</strong></p><p>你可以让 momo 定时扫描指定频道，把重要信息提炼出来——用户反馈频道、竞品讨论频道都适合。</p><p><strong>接入方式</strong>：在 AI 同事或 momo 的对话框上方，点击 Slack 图标即可连接。也可以通过设置 → 集成 → Slack 进入。</p><hr><h2 id="github" tabindex="-1">GitHub <a class="header-anchor" href="#github" aria-label="Permalink to &quot;GitHub&quot;">​</a></h2><p>接入 GitHub 之后，momo 就能同时读懂你们的产品文档和代码——它能做的事会发生质变。</p><p>运营可以让它从代码里读出功能细节写帮助文档。PM 可以让它对比代码和 PRD 找出实现偏差。新人入职不需要问人，直接问 momo 架构是怎么设计的。</p><h3 id="接入步骤" tabindex="-1">接入步骤 <a class="header-anchor" href="#接入步骤" aria-label="Permalink to &quot;接入步骤&quot;">​</a></h3><p><strong>第一步：授权</strong></p><blockquote><p><strong>需要 GitHub 管理员权限</strong>：接入组织仓库时，操作者必须是该 GitHub Organization 的 <strong>Owner 或 Admin</strong>。如果你没有管理员权限，请让团队里有权限的人来完成这一步。</p></blockquote><ol><li>在 Moxt 左侧边栏，点击「设置」→「集成」→「GitHub」</li><li>点击「连接 GitHub」</li><li>选择授权方式： <ul><li><strong>个人账号授权</strong>：接入你个人账号下的仓库</li><li><strong>组织授权</strong>：接入团队组织下的仓库（推荐，需要组织管理员权限）</li></ul></li><li>授权完成后回到 Moxt</li></ol><p><strong>第二步：选择仓库</strong></p><p>授权完成后，选择你想要接入的仓库。建议先接入最核心的一到两个，不需要一次全部接入。</p><p><strong>第三步：验证</strong></p><p>接入完成后，去问 momo 一个关于代码的问题，比如：</p><blockquote><p>&quot;你能看到我们的 GitHub 仓库吗？简单描述一下这个项目的技术架构。&quot;</p></blockquote><h3 id="接入之后你能做什么" tabindex="-1">接入之后你能做什么 <a class="header-anchor" href="#接入之后你能做什么" aria-label="Permalink to &quot;接入之后你能做什么&quot;">​</a></h3><p><strong>让运营自己读懂代码</strong></p><blockquote><p>&quot;从我们的 GitHub 代码里，找出注册流程的限制条件（比如用户名格式、密码要求），整理成一段用户看得懂的说明。&quot;</p></blockquote><p><strong>新人入职速通</strong></p><blockquote><p>&quot;我刚加入这个团队，帮我读一下 GitHub 仓库，用非技术语言解释一下这个产品的核心模块是什么，各自负责什么。&quot;</p></blockquote><p><strong>发现 PRD 和代码的偏差</strong></p><blockquote><p>&quot;对比一下 Workspace 里的注册流程 PRD，和 GitHub 里实际的代码实现，有没有明显的不一致？&quot;</p></blockquote><p><strong>让 momo 直接改代码、提 PR</strong></p><blockquote><p>&quot;帮我把登录页的报错信息从英文改成中文，改完直接提一个 PR。&quot;</p></blockquote><p>momo 会 clone 仓库、创建分支、修改代码、提交 PR，你只需要 review 和合并。</p><hr><h2 id="通用集成-api-key-http" tabindex="-1">通用集成（API Key + HTTP） <a class="header-anchor" href="#通用集成-api-key-http" aria-label="Permalink to &quot;通用集成（API Key + HTTP）&quot;">​</a></h2><p>这是最灵活的接入方式。</p><p><strong>思路</strong>：存一个 API Key，写一段说明告诉 momo 怎么调。momo 执行时自动取密钥、发请求。Mixpanel、BigQuery、Linear、飞书……任何有 HTTP API 的服务都适用。</p><p><strong>典型场景</strong>：</p><ul><li>让 momo 从 Mixpanel 拉数据生成周报</li><li>用飞书 API 自动发通知</li><li>从 BigQuery 查询用户行为数据回答运营问题</li></ul><p><strong>接入方式</strong>：设置 → 集成 → 密钥管理，添加 API Key。然后创建一个 Skill，用自然语言描述 API 的调用方式（endpoint、认证方式、常用操作），momo 就能自动发现并使用。</p><hr><h2 id="mcp-外部工具协议" tabindex="-1">MCP（外部工具协议） <a class="header-anchor" href="#mcp-外部工具协议" aria-label="Permalink to &quot;MCP（外部工具协议）&quot;">​</a></h2><p>MCP 让 momo 像装插件一样获得工具能力——不是调 API 拼请求，而是工具的能力直接变成 momo 的技能。</p><p><strong>典型场景</strong>：</p><ul><li>接入 Sentry MCP → 直接问「最近有什么线上报错？」，momo 像你自己打开 Sentry 一样查询</li><li>接入 Linear MCP → 「帮我创建一个 bug ticket，优先级 high」</li><li>接入 Figma MCP → 「这个设计稿里的按钮用了什么颜色？」</li></ul><p><strong>接入方式</strong>：直接告诉 momo「帮我连接 Sentry」，它会引导你提供 Token，自动完成配置。也可以在设置 → 集成 → MCP 中手动管理。</p><hr><h2 id="webhook" tabindex="-1">Webhook <a class="header-anchor" href="#webhook" aria-label="Permalink to &quot;Webhook&quot;">​</a></h2><p>让外部系统主动通知 Moxt——Sentry 报了错、CI 部署完了、表单收到新提交——都可以通过 Webhook 推过来，momo 自动处理。</p><p><strong>典型场景</strong>：</p><ul><li>Sentry 报错 → momo 自动分析堆栈，如果影响用户超过 100 人，通知 #engineering</li><li>CI 部署完成 → momo 自动跑一轮冒烟测试检查</li><li>Typeform 收到新提交 → momo 自动归类并更新用户反馈汇总</li></ul><p><strong>接入方式</strong>：设置 → 集成 → Webhook → 创建新 Webhook。用自然语言写一段「处理指令」告诉 momo 收到事件后做什么，Moxt 会生成 URL 和 Token，填到外部系统里即可。</p><hr><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>接入方式</th><th>适合场景</th><th>上手成本</th></tr></thead><tbody><tr><td>Slack / GitHub</td><td>高频工具，开箱即用</td><td>低</td></tr><tr><td>通用集成</td><td>任何有 API 的服务，最灵活</td><td>中</td></tr><tr><td>MCP</td><td>让 momo 像装插件一样获得工具能力</td><td>中</td></tr><tr><td>Webhook</td><td>外部系统主动推事件，momo 自动处理</td><td>低</td></tr></tbody></table><p>不确定该选哪种？直接问 momo，它会推荐最适合的方式。</p>',57)])])}const c=t(i,[["render",l]]);export{d as __pageData,c as default};
